import React, { createContext, useState, useEffect, useContext } from 'react';
import { login as apiLogin, register as apiRegister, getProfile, uploadAvatar as apiUploadAvatar } from '../api/auth';
import { getFavorites, addFavorite as apiAddFavorite, removeFavorite as apiRemoveFavorite, checkFavorite } from '../api/favorites';

const CruntRollContext = createContext();

export const useCruntRoll = () => useContext(CruntRollContext);

export const CruntRollProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [loading, setLoading] = useState(true);
  const [favorites, setFavorites] = useState([]);

  // Carregar sessão do token armazenado
  useEffect(() => {
    const token = localStorage.getItem('cruntroll_token');
    if (token) {
      getProfile()
        .then(userData => {
          setUser(userData);
          setIsLoggedIn(true);
          loadFavorites();
        })
        .catch(() => {
          localStorage.removeItem('cruntroll_token');
          setUser(null);
          setIsLoggedIn(false);
        })
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  // Carregar favoritos do usuário logado
  const loadFavorites = async () => {
    try {
      const data = await getFavorites();
      setFavorites(data);
    } catch (error) {
      console.error('Erro ao carregar favoritos:', error);
    }
  };

  const login = async (email, password) => {
    try {
      const data = await apiLogin(email, password);
      localStorage.setItem('cruntroll_token', data.token);
      setUser(data.user);
      setIsLoggedIn(true);
      await loadFavorites();
      return true;
    } catch (error) {
      console.error('Erro no login:', error);
      throw new Error(error.response?.data?.error || 'Erro ao fazer login');
    }
  };

  const register = async (name, email, password) => {
    try {
      const data = await apiRegister(name, email, password);
      localStorage.setItem('cruntroll_token', data.token);
      setUser(data.user);
      setIsLoggedIn(true);
      return true;
    } catch (error) {
      console.error('Erro no registro:', error);
      throw new Error(error.response?.data?.error || 'Erro ao registrar');
    }
  };

  const logout = () => {
    localStorage.removeItem('cruntroll_token');
    setUser(null);
    setIsLoggedIn(false);
    setFavorites([]);
  };

  const addFavorite = async (anime) => {
    try {
      await apiAddFavorite(anime.id, anime);
      await loadFavorites(); // Recarrega a lista completa
      return true;
    } catch (error) {
      console.error('Erro ao adicionar favorito:', error);
      throw new Error(error.response?.data?.error || 'Erro ao adicionar');
    }
  };

  const removeFavorite = async (animeId) => {
    try {
      await apiRemoveFavorite(animeId);
      setFavorites(prev => prev.filter(fav => fav.id !== animeId));
      return true;
    } catch (error) {
      console.error('Erro ao remover favorito:', error);
      throw new Error(error.response?.data?.error || 'Erro ao remover');
    }
  };

  const isFavorite = async (animeId) => {
    // Se estiver logado, consulta a API; se não, retorna false
    if (!isLoggedIn) return false;
    try {
      return await checkFavorite(animeId);
    } catch (error) {
      console.error('Erro ao verificar favorito:', error);
      return false;
    }
  };

  const uploadAvatar = async (file) => {
    try {
      const formData = new FormData();
      formData.append('avatar', file);
      const result = await apiUploadAvatar(formData);
      setUser(result.user);
      return result;
    } catch (error) {
      console.error('Erro ao enviar avatar:', error);
      throw new Error(error.response?.data?.error || 'Erro ao enviar avatar');
    }
  };

  return (
    <CruntRollContext.Provider value={{
      user,
      isLoggedIn,
      loading,
      favorites,
      login,
      register,
      logout,
      addFavorite,
      removeFavorite,
      isFavorite,
      uploadAvatar,
      loadFavorites
    }}>
      {children}
    </CruntRollContext.Provider>
  );
};
